// Init: generate stable executionId, extract webhook payload
const webhookBody = $input.first().json.body || $input.first().json;
const campaignId = webhookBody.campaignId || '';
const criteria = webhookBody.criteria || {};
const userEmail = webhookBody.userEmail || 'danny.reszka@gmail.com';

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

// One stable ID per workflow execution — reused on retries
const executionId = ($execution && $execution.id) ? $execution.id.replace(/-/g, '').slice(0, 32) : uuidv4();
const backendUrl = webhookBody.backendUrl || '';
const backendApiKey = webhookBody.backendApiKey || '';
const serperApiKey = webhookBody.serperApiKey || '';
const groqApiKey = webhookBody.groqApiKey || '';

return [{ json: {
  executionId,
  campaignId,
  criteria,
  userEmail,
  backendUrl,
  backendApiKey,
  serperApiKey,
  groqApiKey,
  updatedAt: new Date().toISOString(),
  source: 'n8n',
} }];

// Process Serper organic results — normalise into per-company items.
// Output items keep the same shape downstream nodes expect; contact
// fields stay empty since Serper returns websites, not people —
// Hunter/Clay fill them in later when given a domain.
const initData = $('Code: Init Execution').first().json;
const existingLeadsResp = $('HTTP: GET Existing Leads').first().json;
const serperData = $input.first().json;

const existingLeads = (existingLeadsResp.data || []);
const organic = serperData.organic || [];

const SKIP_HOSTS = [
  'linkedin.com','twitter.com','x.com','facebook.com','instagram.com','youtube.com','tiktok.com',
  'wikipedia.org','crunchbase.com','glassdoor.com','indeed.com','zoominfo.com','rocketreach.co',
  'bloomberg.com','reuters.com','nytimes.com','ft.com','forbes.com','businessinsider.com','techcrunch.com',
  'medium.com','substack.com','quora.com','yelp.com','tripadvisor.com','google.com','youtube.com'
];

function cleanCompanyName(title) {
  if (!title) return '';
  let name = title.split(/\s+[-|—–:]\s+/)[0].trim();
  name = name.replace(/\b(home|homepage|about|about us|contact|careers|jobs|login|sign in|index)\s*$/i, '').trim();
  return name;
}

function extractHost(url) {
  if (!url) return '';
  try { return new URL(url).hostname.replace(/^www\./, '').toLowerCase(); }
  catch (e) { return ''; }
}

function isSkipped(host) {
  if (!host) return true;
  for (const h of SKIP_HOSTS) {
    if (host === h || host.endsWith('.' + h)) return true;
  }
  return false;
}

const seen = new Set();
const items = [];
for (let i = 0; i < organic.length; i++) {
  const r = organic[i];
  const host = extractHost(r.link);
  if (isSkipped(host)) continue;
  if (seen.has(host)) continue;
  seen.add(host);
  const companyName = cleanCompanyName(r.title);
  if (!companyName || companyName.length < 2) continue;
  items.push({
    personName: '',
    personTitle: '',
    personEmail: '',
    personPhone: '',
    companyName: companyName,
    domain: host,
    website: r.link || '',
    industry: '',
    headcount: null,
    fundingStage: '',
    linkedinUrl: '',
    executionId: initData.executionId,
    campaignId: initData.campaignId,
    criteria: initData.criteria,
    userEmail: initData.userEmail,
    backendUrl: initData.backendUrl,
    backendApiKey: initData.backendApiKey,
    serperApiKey: initData.serperApiKey,
    groqApiKey: initData.groqApiKey,
    updatedAt: initData.updatedAt,
    source: initData.source,
    existingLeads,
    itemIndex: items.length,
  });
}

if (items.length === 0) {
  return [{ json: {
    ...initData,
    existingLeads,
    noResults: true,
    companyName: '__NO_RESULTS__',
    itemIndex: 0,
  } }];
}

return items.map(item => ({ json: item }));

// Parse Claude score, check qualifying, check duplicate
const lead = $('Loop: Per Lead').item.json;
const claudeResp = $input.first().json;

// Parse score from Claude response
let score = 0;
let reasoning = '';
try {
  const text = (claudeResp.choices && claudeResp.choices[0] && claudeResp.choices[0].message) ? claudeResp.choices[0].message.content : '';
  reasoning = text.slice(0, 200);
  const m = text.match(/Score:\s*(\d+(?:\.\d+)?)/i) ||
             text.match(/(\d+(?:\.\d+)?)\s*\/\s*10/i) ||
             text.match(/\b(10|[1-9])\b/);
  if (m) score = parseFloat(m[1]);
} catch (e) {
  reasoning = 'parse-error: ' + e.message;
}

const QUALIFY_THRESHOLD = 6;
const isQualifying = score >= QUALIFY_THRESHOLD;

// Duplicate check: match by domain then by company name
const existingLeads = lead.existingLeads || [];
const domain = (lead.domain || '').toLowerCase();
const companyName = (lead.companyName || '').toLowerCase().trim();
let isDuplicate = false;
let existingLeadId = null;

if (domain) {
  const match = existingLeads.find(l => {
    const ld = ((l.website || l.domain || '')
      .replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0]).toLowerCase();
    return ld && ld === domain;
  });
  if (match) { isDuplicate = true; existingLeadId = match.id; }
}
if (!isDuplicate && companyName) {
  const match = existingLeads.find(l =>
    (l.company || l.name || '').toLowerCase().trim() === companyName
  );
  if (match) { isDuplicate = true; existingLeadId = match.id; }
}

// Per-lead requestId: stable per execution + lead index
const leadRequestId = $execution.id + '-lead-' + lead.itemIndex;

return [{ json: {
  ...lead,
  score,
  reasoning,
  isQualifying,
  isDuplicate,
  existingLeadId,
  leadRequestId,
  // Create new lead only when qualifying AND not a duplicate
  shouldCreate: isQualifying && !isDuplicate,
  // Link existing lead only when qualifying AND is a duplicate
  shouldLink: isQualifying && isDuplicate,
} }];
